⟦Σ:Types⟧{
  QueryKey≜{key:String, ttl:Integer}
  CacheResult≜{hit:Boolean, data:Any, age:Integer}
  DBResult≜{rows:List, count:Integer, latency:Integer}
  CacheEntry≜{key:String, value:Any, expires_at:Integer}
  Response≜{source:Enum{cache,database}, payload:Any}
}

⟦Γ:Rules⟧{
  ∀q:QueryKey:key(q)∈String ∧ ttl(q)>0
  ∀r:CacheResult:hit(r)=true ⇒ data(r)≠∅ ∧ age(r)≤ttl(query)
  hit(cache,query)=true ⇒ return(CacheResult) ∧ ¬exec(db_query)
  hit(cache,query)=false ⇒ exec(db_query) ∧ exec(cache_write) ∧ return(DBResult)
  ∀e:CacheEntry:expires_at(e)≔now()+ttl(query)
}

⟦Λ:Funcs⟧{
  check_cache≜λ(q:QueryKey).lookup(cache,key(q))→CacheResult
  query_db≜λ(q:QueryKey).select(database,key(q))→DBResult
  update_cache≜λ(q:QueryKey,r:DBResult).write(cache,CacheEntry{key(q),rows(r),now()+ttl(q)})→Boolean
  resolve≜λ(q:QueryKey).
    (check_cache(q).hit=true
      → Response{source≔cache, payload≔data(check_cache(q))}
    | query_db(q)→r: update_cache(q,r) ∧ Response{source≔database, payload≔rows(r)})
}

