}

⟦Σ:Types⟧{
  Source≜{api_source, db_source}
  Stage≜{extract, transform, load, error_queue}
  ValidationResult≜{pass, fail}
  ExtractPayload≜{data:Any, source:Source, timestamp:Int}
  TransformPayload≜{data:Any, rules:List[Rule], result:ValidationResult}
  LoadTarget≜{data_warehouse, error_queue}
  Rule≜{id:String, predicate:Func, severity:String}
}

⟦Γ:Rules⟧{
  ∀s∈Source: extract(s)→ExtractPayload
  extract(api_source) ∥ extract(db_source)
  combine(extract(api_source), extract(db_source))→transform_input
  ∀r∈Rules: apply(r, transform_input)→ValidationResult
  ValidationResult=pass ⇒ load(data_warehouse)
  ValidationResult=fail ⇒ route(error_queue)
  ¬(load(data_warehouse) ∧ route(error_queue))
}

⟦Λ:Funcs⟧{
  extract≜λ(src:Source).fetch(src)→ExtractPayload
  combine≜λ(p1:ExtractPayload, p2:ExtractPayload).merge(p1.data, p2.data)
  validate≜λ(data:Any, rules:List[Rule]).∀r∈rules:r.predicate(data)
  transform≜λ(combined:Any).{data:combined, result:validate(combined, Rules)}
  load≜λ(target:LoadTarget, payload:Any).write(target, payload)
  route_pipeline≜λ(payload:TransformPayload).
    (payload.result=pass → load(data_warehouse, payload.data))
    ∨ (payload.result=fail → load(error_queue, payload.data))
  run≜λ().
    extract(api_source) ∥ extract(db_source)
    → combine
    → transform
    → route_pipeline
}

